import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { ProductService } from '../../core/services/product.service';
import { CartService } from '../../core/services/cart.service';
import { AuthService } from '../../core/services/auth.service';
import { Product } from '../../core/models';
import { formatPrice } from '../../core/api';

@Component({
  selector: 'app-product-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './product-detail.component.html',
  styleUrl: './product-detail.component.css',
})
export class ProductDetailComponent {
  private readonly productService = inject(ProductService);
  private readonly cartService = inject(CartService);
  private readonly auth = inject(AuthService);
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);

  readonly format = formatPrice;

  readonly product = signal<Product | null>({
    id: '1',
    name: 'CLASS-J Time-Delay Fuse 30A',
    description:
      '600V industrial time-delay fuse engineered for motor, transformer and welder circuits. UL Listed, current-limiting design with a 200kA interrupting rating. Rejection-style body prevents mis-application in branch circuits.',
    priceCents: 1899,
    imageUrl: null,
    stockQty: 120,
  });

  readonly qty = signal<number>(1);
  readonly adding = signal<boolean>(false);
  readonly added = signal<boolean>(false);
  readonly errorMessage = signal<string>('');

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.productService.get(id).subscribe({
      next: (p) => this.product.set(p),
      error: () => {},
    });
  }

  dec(): void {
    this.qty.update((q) => Math.max(1, q - 1));
  }

  inc(): void {
    const max = this.product()?.stockQty ?? 1;
    this.qty.update((q) => Math.min(Math.max(1, max), q + 1));
  }

  addToCart(): void {
    const p = this.product();
    if (!p) return;
    if (!this.auth.isLoggedIn()) {
      this.router.navigate(['/login'], { queryParams: { redirect: `/products/${p.id}` } });
      return;
    }
    this.adding.set(true);
    this.errorMessage.set('');
    this.cartService.addItem(p.id, this.qty()).subscribe({
      next: () => {
        this.adding.set(false);
        this.added.set(true);
      },
      error: (err) => {
        this.adding.set(false);
        this.errorMessage.set(err?.error?.message ?? 'Could not add to cart.');
      },
    });
  }
}
